+/**
+ * SMS notification adapter — delivers notifications via SMS.
+ *
+ * Formats notification payloads as short text messages and sends them
+ * to a phone number recipient. Implements the NotificationAdapter interface
+ * required by the notification system's event-driven architecture.
+ *
+ * NOTE: This is a stub adapter (like email and webhook adapters) — it records
+ * messages in-memory rather than sending via a real SMS gateway. Real SMS
+ * delivery (e.g. via Twilio, AWS SNS) would be added when integrating with
+ * a real transport layer.
+ */
+
+import type { NotificationAdapter } from './notification.adapter.js';
+import type { NotificationPayload, NotificationResult } from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+export interface SmsConfig {
+  /** Sender ID or phone number (e.g. "+15551234567" or "TaskFlow"). */
+  fromNumber: string;
+  /** Maximum message length in characters (default: 160). */
+  maxLength?: number;
+}
+
+export interface SentSms {
+  from: string;
+  to: string;
+  body: string;
+  sentAt: Date;
+}
+
+const PHONE_REGEX = /^\+[1-9]\d{6,14}$/;
+
+export class SmsNotificationAdapter implements NotificationAdapter {
+  readonly channel = 'sms';
+  private logger = new Logger('SmsAdapter');
+  private sentMessages: SentSms[] = [];
+
+  constructor(private config: SmsConfig) {}
+
+  /**
+   * Validate that a recipient string is a well-formed E.164 phone number.
+   */
+  validateRecipient(recipient: string): boolean {
+    return PHONE_REGEX.test(recipient);
+  }
+
+  /**
+   * Format a notification payload into an SMS-appropriate text body.
+   * Truncates to maxLength (default 160) with an ellipsis if needed.
+   */
+  formatMessage(payload: NotificationPayload): string {
+    const maxLength = this.config.maxLength ?? 160;
+    const message = `${payload.subject}: ${payload.body}`;
+
+    if (message.length <= maxLength) {
+      return message;
+    }
+    return message.slice(0, maxLength - 3) + '...';
+  }
+
+  /**
+   * Send an SMS notification.
+   *
+   * 1. Validates the recipient phone number.
+   * 2. Formats the message body with truncation.
+   * 3. Records the SMS and returns the result.
+   *
+   * Never throws — returns a failed NotificationResult on error.
+   */
+  async send(payload: NotificationPayload): Promise<NotificationResult> {
+    if (!this.validateRecipient(payload.recipient)) {
+      this.logger.warn(`Invalid recipient phone number: ${payload.recipient}`);
+      return {
+        success: false,
+        notificationId: payload.id,
+        channel: 'sms',
+        error: `Invalid recipient phone number: ${payload.recipient}`,
+        deliveredAt: new Date(),
+      };
+    }
+
+    const body = this.formatMessage(payload);
+
+    this.logger.info(`Sending SMS to ${payload.recipient}: ${body.slice(0, 40)}...`);
+
+    const sms: SentSms = {
+      from: this.config.fromNumber,
+      to: payload.recipient,
+      body,
+      sentAt: new Date(),
+    };
+
+    this.sentMessages.push(sms);
+
+    return {
+      success: true,
+      notificationId: payload.id,
+      channel: 'sms',
+      deliveredAt: sms.sentAt,
+    };
+  }
+
+  /**
+   * Get all sent SMS messages. Useful for testing.
+   */
+  getSentMessages(): SentSms[] {
+    return [...this.sentMessages];
+  }
+
+  /**
+   * Clear sent SMS messages. Useful for testing.
+   */
+  clearSentMessages(): void {
+    this.sentMessages = [];
+  }
+}

