import { describe, it, expect, beforeEach } from 'vitest';
import { SmsNotificationAdapter } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    recipient: '+15551234567',
    subject: 'Order #123',
    body: 'Widget x2. Total: $20.00',
    channel: 'sms',
    ...overrides,
  };
}

describe('SmsNotificationAdapter', () => {
  let adapter: SmsNotificationAdapter;

  beforeEach(() => {
    adapter = new SmsNotificationAdapter({
      fromNumber: '+15559876543',
    });
  });

  describe('channel', () => {
    it('should report "sms" as its channel', () => {
      expect(adapter.channel).toBe('sms');
    });
  });

  describe('validateRecipient', () => {
    it('should accept valid E.164 phone numbers', () => {
      expect(adapter.validateRecipient('+15551234567')).toBe(true);
      expect(adapter.validateRecipient('+441234567890')).toBe(true);
      expect(adapter.validateRecipient('+8613800138000')).toBe(true);
    });

    it('should reject invalid phone numbers', () => {
      expect(adapter.validateRecipient('')).toBe(false);
      expect(adapter.validateRecipient('5551234567')).toBe(false);
      expect(adapter.validateRecipient('+0123456')).toBe(false);
      expect(adapter.validateRecipient('not-a-number')).toBe(false);
      expect(adapter.validateRecipient('user@example.com')).toBe(false);
      expect(adapter.validateRecipient('+1')).toBe(false);
    });
  });

  describe('formatMessage', () => {
    it('should combine subject and body', () => {
      const payload = makePayload();
      const message = adapter.formatMessage(payload);

      expect(message).toBe('Order #123: Widget x2. Total: $20.00');
    });

    it('should truncate long messages to 160 characters by default', () => {
      const payload = makePayload({
        subject: 'Important Notification',
        body: 'A'.repeat(200),
      });
      const message = adapter.formatMessage(payload);

      expect(message.length).toBe(160);
      expect(message.endsWith('...')).toBe(true);
    });

    it('should not truncate messages within limit', () => {
      const payload = makePayload({ subject: 'Hi', body: 'Short' });
      const message = adapter.formatMessage(payload);

      expect(message).toBe('Hi: Short');
      expect(message.endsWith('...')).toBe(false);
    });

    it('should respect custom maxLength', () => {
      const customAdapter = new SmsNotificationAdapter({
        fromNumber: '+15559876543',
        maxLength: 50,
      });
      const payload = makePayload({
        subject: 'Order Update',
        body: 'Your order has been shipped and is on its way to you',
      });
      const message = customAdapter.formatMessage(payload);

      expect(message.length).toBe(50);
      expect(message.endsWith('...')).toBe(true);
    });
  });

  describe('send', () => {
    it('should send successfully with valid phone number', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('sms');
      expect(result.deliveredAt).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();
    });

    it('should fail for invalid phone number', async () => {
      const payload = makePayload({ recipient: 'not-a-phone' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid recipient phone number');
    });

    it('should record sent messages with correct fields', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const messages = adapter.getSentMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]?.from).toBe('+15559876543');
      expect(messages[0]?.to).toBe('+15551234567');
      expect(messages[0]?.body).toBe('Order #123: Widget x2. Total: $20.00');
      expect(messages[0]?.sentAt).toBeInstanceOf(Date);
    });

    it('should not record message when phone number is invalid', async () => {
      const payload = makePayload({ recipient: 'bad' });
      await adapter.send(payload);
      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should handle multiple sends independently', async () => {
      await adapter.send(makePayload({ id: 'n1' }));
      await adapter.send(makePayload({ id: 'n2' }));

      const messages = adapter.getSentMessages();
      expect(messages).toHaveLength(2);
    });
  });

  describe('clearSentMessages', () => {
    it('should clear the sent messages list', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentMessages()).toHaveLength(1);

      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });
  });

  describe('integration with NotificationService', () => {
    it('should work when registered as an adapter', async () => {
      // Verify the adapter conforms to the NotificationAdapter interface
      expect(adapter.channel).toBe('sms');
      expect(typeof adapter.send).toBe('function');

      const result = await adapter.send(makePayload());
      expect(result.success).toBe(true);
      expect(result.channel).toBe('sms');
    });
  });
});
